  ('judicial-57112235-moex-00377', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '下列毒品戒治模式中，何者強調毒品犯之成癮係意志薄弱、性格惡劣所致，主張採取嚴厲、強迫 的懲罰方式，才能達到毒品戒治的目的？', '["道德模式", "疾病／醫療的模式", "自療模式", "生物心理社會模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00378', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '女性犯罪者被刑事司法體系忽略之原因，下列敘述何者錯誤？', '["女性犯罪人口少，僅占在監收容人總數約1成上下", "罪質與犯罪型態，大部分以暴力犯罪為主", "在監行狀表現普遍良好，極少有重大戒護事故發生", "受傳統儒家禮教束縛，社會對女性寬容度較高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00379', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄戒護勤務配置之原則，下列敘述何者錯誤？', '["勤務安排，務求日夜能循環銜接各戒護重點，不可使其中斷致生戒護漏洞", "分配勤務，應把握由「內部管理至外圍警戒，由大崗位到小崗位」之原則循序漸進安排", "對於值勤人員之休息及睡眠時間，應作合理之安排", "警力集中控制，以利勤務調遣，並預留警力，以備不時之需"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00380', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關美國學者菲勒（Wheeler,1961）提出之監獄受刑人U字型適應模式，下列敘述何者正確？', '["受刑人在初入監開始前3個月，呈現出低度服從之現象", "受刑人在監禁中期，呈現出服從程度最高的現象", "受刑人出獄前6個月，又呈現出高度服從之現象", "受刑人入監後之U字型適應模式，與其週遭環境毫無相關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00381', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄建築規劃時應注意之原則，下列敘述何者錯誤？', '["著重個別化與分類處遇的設計以避免犯罪學習", "監獄建築應切合時代的需求、配合矯正的理念", "建築空間應以受刑人自由與舒適為前提", "規劃時需有前瞻性，不宜遷就預算而因陋就簡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00382', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關受刑人進行地下經濟活動之動機，下列敘述何者錯誤？', '["解除毒癮：在獄中設法走私毒品以為解癮", "道德提升：在監獄自我磨練，提升心靈層次", "在監地位：持有現金、通訊器材，展現在監行情", "保護自身：為保護自己遂走私工具以為因應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00383', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關矯正機構經營管理的成功關鍵，下列敘述何者錯誤？', '["爭取預算與資源，並依其優先順序做出妥適的安排與分配", "保障升遷機會與管道，提高戒護津貼、值勤費以激勵士氣", "採由上而下之單向決策模式，以保障決策的果斷與執行速度", "機構成員皆能善盡其職，以既定的資源發揮最大的效果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00384', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '下列何者係提出受刑人進入監獄服刑後，對監獄社會風俗、習慣、價值觀的適應與同化而形成監 獄化的學者？', '["克雷莫（DonaldClemmer,1940）", "歐文（JohnIrwin,1970）", "賽克斯（GreshamSykes,1958）", "狄流里歐（Jr.JohnDilulio,1987）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00385', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄戒護事故的防範對策，下列敘述何者錯誤？', '["建立受刑人懲罰審查制度，妥善處理不服懲罰而提出申訴之個案", "運用15日以上隔離保護措施，以防患未然", "解決受刑人過度擁擠問題，以減少衝突摩擦事故", "調劑受刑人身心，改善職員與受刑人之關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
